INSERT INTO prs_options (option_id, question_id, option_label, option_value, points, display_order, status, created_at) VALUES
('DN-4/009/02', 'DN-4/009', 'Yes', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DN-4/010/01', 'DN-4/010', 'No', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DN-4/010/02', 'DN-4/010', 'Yes', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/001/01', 'DSRS/001', 'Normal memory.', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/001/02', 'DSRS/001', 'Occasionally forgets things that they were told recently. Does not cause many problems.', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/001/03', 'DSRS/001', 'Mild consistent forgetfulness. Remembers recent events but often forgets parts.', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/001/04', 'DSRS/001', 'Moderate memory loss. Worse for recent events. May not remember something you just told them. Causes problems with everyday activities.', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/001/05', 'DSRS/001', 'Substantial memory loss. Quickly forgets recent or newly-learned things. Can only remember things that they have known for a long time.', '4', 4, 5, true, '2026-09-04 00:00:00+00'),
('DSRS/001/06', 'DSRS/001', 'Does not remember basic facts like the day of the week, when last meal was eaten or what the next meal will be.', '5', 5, 6, true, '2026-09-04 00:00:00+00'),
('DSRS/001/07', 'DSRS/001', 'Does not remember even the most basic things.', '6', 6, 7, true, '2026-09-04 00:00:00+00'),
('DSRS/002/01', 'DSRS/002', 'Normal ability to talk and to understand others.', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/002/02', 'DSRS/002', 'Sometimes cannot find a word, but able to carry on conversations.', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/002/03', 'DSRS/002', 'Often forgets words. May use the wrong word in its place. Some trouble expressing thoughts and giving answers.', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/002/04', 'DSRS/002', 'Usually answers questions using sentences but rarely starts a conversation.', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/002/05', 'DSRS/002', 'Answers questions, but responses are often hard to understand or don''t make sense. Usually able to follow simple instructions.', '4', 4, 5, true, '2026-09-04 00:00:00+00'),
('DSRS/002/06', 'DSRS/002', 'Speech often does not make sense. Can not answer questions or follow instructions.', '5', 5, 6, true, '2026-09-04 00:00:00+00'),
('DSRS/002/07', 'DSRS/002', 'Does not respond most of the time.', '6', 6, 7, true, '2026-09-04 00:00:00+00'),
('DSRS/003/01', 'DSRS/003', 'Normal - recognizes people and generally knows who they are.', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/003/02', 'DSRS/003', 'Usually recognizes grandchildren, cousins or relatives who are not seen frequently but may not recall how they are related.', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/003/03', 'DSRS/003', 'Usually does not recognize family members who are not seen frequently. Is often confused about how family members such as grandchildren, nieces, or nephews are related to them.', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/003/04', 'DSRS/003', 'Sometimes does not recognize close family members or others who they see frequently. May not recognize their children, brothers, or sisters who are not seen on a regular basis.', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/003/05', 'DSRS/003', 'Frequently does not recognize spouse or caregiver.', '4', 4, 5, true, '2026-09-04 00:00:00+00'),
('DSRS/003/06', 'DSRS/003', 'No recognition or awareness of the presence of others.', '5', 5, 6, true, '2026-09-04 00:00:00+00'),
('DSRS/004/01', 'DSRS/004', 'Normal awareness of time of day and day of week.', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/004/02', 'DSRS/004', 'Some confusion about what time it is or what day of the week, but not severe enough to interfere with everyday activities.', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/004/03', 'DSRS/004', 'Frequently confused about time of day.', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/004/04', 'DSRS/004', 'Almost always confused about the time of day.', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/004/05', 'DSRS/004', 'Seems completely unaware of time.', '4', 4, 5, true, '2026-09-04 00:00:00+00'),
('DSRS/005/01', 'DSRS/005', 'Normal awareness of where they are even in new places.', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/005/02', 'DSRS/005', 'Sometimes disoriented in new places.', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/005/03', 'DSRS/005', 'Frequently disoriented in new places.', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/005/04', 'DSRS/005', 'Usually disoriented, even in familiar places. May forget that they are already at home.', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/005/05', 'DSRS/005', 'Almost always confused about place.', '4', 4, 5, true, '2026-09-04 00:00:00+00'),
('DSRS/006/01', 'DSRS/006', 'Normal - as able to make decisions as before.', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/006/02', 'DSRS/006', 'Only some difficulty making decisions that arise in day-to-day life.', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/006/03', 'DSRS/006', 'Moderate difficulty. Gets confused when things get complicated or plans change.', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/006/04', 'DSRS/006', 'Rarely makes any important decisions. Gets confused easily.', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/006/05', 'DSRS/006', 'Not able to understand what is happening most of the time.', '4', 4, 5, true, '2026-09-04 00:00:00+00'),
('DSRS/007/01', 'DSRS/007', 'Normal - acts the same with people as before', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/007/02', 'DSRS/007', 'Only mild problems that are not really important, but clearly acts differently from previous years.', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/007/03', 'DSRS/007', 'Can still take part in community activities without help. May appear normal to people who don''t know them.', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/007/04', 'DSRS/007', 'Often has trouble dealing with people outside the home without help from caregiver. Usually can participate in quiet home activities with friends. The problem is clear to anyone who sees them.', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/007/05', 'DSRS/007', 'No longer takes part in any real way in activities at home involving other people. Can only deal with the primary caregiver.', '4', 4, 5, true, '2026-09-04 00:00:00+00'),
('DSRS/007/06', 'DSRS/007', 'Little or no response even to primary caregiver.', '5', 5, 6, true, '2026-09-04 00:00:00+00'),
('DSRS/008/01', 'DSRS/008', 'Normal. No decline in ability to do things around the house.', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/008/02', 'DSRS/008', 'Some problems with home activities. May have more trouble with money management (paying bills) and fixing things. Can still go to a store, cook or clean. Still watches TV or reads a newspaper with interest and understanding.', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/008/03', 'DSRS/008', 'Makes mistakes with easy tasks like going to a store, cooking or cleaning. Losing interest in the newspaper, TV or radio. Often can''t follow a long conversation on a single topic.', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/008/04', 'DSRS/008', 'Not able to shop, cook or clean without a lot of help. Does not understand the newspaper or the TV. Cannot follow a conversation.', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/008/05', 'DSRS/008', 'No longer does any home-based activities.', '4', 4, 5, true, '2026-09-04 00:00:00+00'),
('DSRS/009/01', 'DSRS/009', 'Normal. Takes care of self as well as they used to.', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/009/02', 'DSRS/009', 'Sometimes forgets to wash, shave, comb hair, or may dress in wrong type of clothes. Not as neat as they used to be.', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/009/03', 'DSRS/009', 'Requires help with dressing, washing and personal grooming.', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/009/04', 'DSRS/009', 'Totally dependent on help for personal care.', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/010/01', 'DSRS/010', 'Normal, does not need help in eating food that is served to them.', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/010/02', 'DSRS/010', 'May need help cutting food or have trouble with some foods, but basically able to eat by themselves.', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/010/03', 'DSRS/010', 'Generally able to feed themselves but may require some help. May lose interest during the meal.', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/010/04', 'DSRS/010', 'Needs to be fed. May have trouble swallowing.', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/011/01', 'DSRS/011', 'Normal - does not have problems controlling urination or bowels except for physical problems.', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/011/02', 'DSRS/011', 'Rarely fails to control urination (generally less than one accident per month).', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/011/03', 'DSRS/011', 'Occasional failure to control urination (about once a week or less).', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/011/04', 'DSRS/011', 'Frequently fails to control urination (more than once a week).', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/011/05', 'DSRS/011', 'Generally fails to control urination and frequently can not control bowels.', '4', 4, 5, true, '2026-09-04 00:00:00+00'),
('DSRS/012/01', 'DSRS/012', 'Normal, able to get around on their own. (May have physical problems that require a cane or walker).', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
('DSRS/012/02', 'DSRS/012', 'Sometimes gets confused when driving or taking public transportation, especially in new places. Able to walk places alone.', '1', 1, 2, true, '2026-09-04 00:00:00+00'),
('DSRS/012/03', 'DSRS/012', 'Cannot drive or take public transportation alone, even in familiar places. Can walk alone outside for short distances. Might get lost if walking too far from home.', '2', 2, 3, true, '2026-09-04 00:00:00+00'),
('DSRS/012/04', 'DSRS/012', 'Cannot be left outside alone. Can get around the house without getting lost or confused.', '3', 3, 4, true, '2026-09-04 00:00:00+00'),
('DSRS/012/05', 'DSRS/012', 'Gets confused and needs help finding their way around the house.', '4', 4, 5, true, '2026-09-04 00:00:00+00'),
('DSRS/012/06', 'DSRS/012', 'Almost always in a bed or chair. May be able to walk a few steps with help, but lacks sense of direction.', '5', 5, 6, true, '2026-09-04 00:00:00+00'),
('DSRS/012/07', 'DSRS/012', 'Always in bed. Unable to sit or stand.', '6', 6, 7, true, '2026-09-04 00:00:00+00'),
