('MADRS/008/07', 'MADRS/008', 'The experience of being emotionally paralysed, inability to feel anger, grief or pleasure and a complete or even painful failure to feel for close relatives and friends.', '6', 6, 7, true, '2026-09-04 00:00:00+00'),
('MADRS/009/01', 'MADRS/009', 'No pessimistic thoughts.', '0', 0, 1, true, '2026-09-04 00:00:00+00'),
